/**
 * Список преподавателей. Источник: DEMO_TEACHERS bundled (всегда),
 * + DEMO_CLASSROOMS / DEMO_STUDENTS / DEMO_SLOTS для агрегатов (классы / ученики / слоты на этой неделе).
 */

import { useMemo } from 'react'
import PlatformShell from '../components/PlatformShell'
import { DEMO_TEACHERS, DEMO_CLASSROOMS, DEMO_STUDENTS, DEMO_SLOTS } from '../lib/kidsTeachingDemoData'

export default function AdminTeachers() {
  const rows = useMemo(() => {
    const now = Date.now()
    const in7  = now + 7 * 86400000
    return DEMO_TEACHERS.map((t) => {
      const classes  = DEMO_CLASSROOMS.filter((c) => c.teacherId === t.id)
      const classIds = new Set(classes.map((c) => c.id))
      const students = DEMO_STUDENTS.filter((s) => s.classroomId && classIds.has(s.classroomId))
      const wkSlots  = DEMO_SLOTS.filter((s) => {
        if (s.teacherId !== t.id) return false
        const dt = new Date(s.datetime).getTime()
        return dt >= now && dt <= in7
      })
      return { ...t, classes, students, wkSlots }
    }).sort((a, b) => b.students.length - a.students.length)
  }, [])

  return (
    <PlatformShell activeKey="admin">
      <div className="kb-cover kb-cover--violet">
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontSize: 36 }} aria-hidden>🎓</span>
          <div>
            <div className="eyebrow" style={{ color: 'rgba(255,255,255,0.7)' }}>Команда</div>
            <h1 className="h1" style={{ margin: 0, color: '#fff' }}>Преподаватели · {DEMO_TEACHERS.length}</h1>
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 1100, margin: '0 auto', padding: '28px 16px' }}>
        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
            <thead>
              <tr style={{ background: 'var(--paper-2, #f9f8ff)' }}>
                <th style={th}>Имя</th>
                <th style={th}>Логин</th>
                <th style={th}>Пароль</th>
                <th style={th}>Классов</th>
                <th style={th}>Учеников</th>
                <th style={th}>Слотов на неделе</th>
                <th style={th}>Группы</th>
              </tr>
            </thead>
            <tbody>
              {rows.map((r) => (
                <tr key={r.id} style={{ borderTop: '1px solid var(--paper-3, #e5e2f0)' }}>
                  <td style={{ ...td, fontWeight: 700 }}>{r.name}</td>
                  <td style={{ ...td, fontFamily: 'monospace', color: 'var(--violet)' }}>{r.login}</td>
                  <td style={{ ...td, fontFamily: 'monospace', color: 'var(--ink-soft)', fontSize: 12 }}>Eduson2026!</td>
                  <td style={td}>{r.classes.length}</td>
                  <td style={td}>{r.students.length}</td>
                  <td style={td}>{r.wkSlots.length}</td>
                  <td style={{ ...td, fontSize: 12, color: 'var(--ink-soft)' }}>
                    {r.classes.map(c => c.name).join(', ') || '—'}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div style={{ marginTop: 24, padding: 16, background: 'var(--violet-soft, #f3f0ff)', borderRadius: 12, fontSize: 13, color: 'var(--ink-soft)' }}>
          💡 Список преподавателей загружен из таблицы kids-teaching (53 ученика, ~50 групп, 8 нед расписания).
          Когда production-бэкенд поднимется и пройдёт seed — данные подтянутся из БД (с реальными ID и историей входов).
        </div>
      </div>
    </PlatformShell>
  )
}

const th: React.CSSProperties = { padding: '10px 12px', textAlign: 'left', fontWeight: 700, fontSize: 12, textTransform: 'uppercase', letterSpacing: 1, color: 'var(--ink-soft)' }
const td: React.CSSProperties = { padding: '10px 12px' }
